export interface PayloadDebouncer {
  accept(payload: string): boolean;
  reset(): void;
}

export function createPayloadDebouncer(windowMs: number): PayloadDebouncer {
  let lastPayload: string | null = null;
  let lastTime = 0;

  return {
    accept(payload: string): boolean {
      const now = performance.now();
      if (lastPayload === payload && now - lastTime < windowMs) {
        return false;
      }
      lastPayload = payload;
      lastTime = now;
      return true;
    },
    reset(): void {
      lastPayload = null;
      lastTime = 0;
    },
  };
}
