import type { ScannerError } from '../types';

export interface UseCameraOptions {
  videoConstraints?: MediaTrackConstraints;
  preferZoom?: number;
  onError?: (err: ScannerError) => void;
  onActiveChange?: (active: boolean) => void;
}

export interface CameraInstance {
  readonly active: boolean;
  readonly videoWidth: number;
  readonly videoHeight: number;
  readonly stream: MediaStream | null;
  start: (video: HTMLVideoElement) => Promise<void>;
  stop: () => void;
}

const DEFAULT_CONSTRAINTS: MediaTrackConstraints = {
  facingMode: { ideal: 'environment' },
  width: { ideal: 1920 },
  height: { ideal: 1080 },
  frameRate: { ideal: 30 },
};

export function useCamera(opts: UseCameraOptions = {}): CameraInstance {
  let stream: MediaStream | null = null;
  let active = false;
  let videoWidth = 0;
  let videoHeight = 0;

  function setActive(next: boolean) {
    if (active !== next) {
      active = next;
      opts.onActiveChange?.(active);
    }
  }

  async function start(video: HTMLVideoElement): Promise<void> {
    if (active) return;
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
      const err: ScannerError = {
        code: 'camera_unavailable',
        message: 'getUserMedia is not available',
      };
      opts.onError && opts.onError(err);
      throw new Error(err.message);
    }

    const baseConstraints: MediaTrackConstraints = {
      ...DEFAULT_CONSTRAINTS,
      ...(opts.videoConstraints || {}),
    };

    let mediaStream: MediaStream;
    try {
      mediaStream = await navigator.mediaDevices.getUserMedia({
        audio: false,
        video: baseConstraints,
      });
    } catch (e) {
      try {
        mediaStream = await navigator.mediaDevices.getUserMedia({
          audio: false,
          video: {
            ...baseConstraints,
            width: { ideal: 1280 },
            height: { ideal: 720 },
          },
        });
      } catch (e2) {
        const err: ScannerError = {
          code:
            e instanceof DOMException && e.name === 'NotAllowedError'
              ? 'camera_denied'
              : 'camera_unavailable',
          message: e2 instanceof Error ? e2.message : String(e2),
          cause: e2,
        };
        opts.onError && opts.onError(err);
        throw e2;
      }
    }

    if (opts.preferZoom && opts.preferZoom > 1) {
      const track = mediaStream.getVideoTracks()[0];
      const caps = (track.getCapabilities ? track.getCapabilities() : {}) as MediaTrackCapabilities & {
        zoom?: { min: number; max: number; step: number };
      };
      if (caps.zoom) {
        const z = Math.min(
          Math.max(opts.preferZoom, caps.zoom.min),
          caps.zoom.max,
        );
        try {
          await track.applyConstraints({
            advanced: [{ zoom: z } as MediaTrackConstraintSet],
          });
        } catch {
          // ignore: zoom is best-effort
        }
      }
    }

    stream = mediaStream;
    video.srcObject = mediaStream;
    video.setAttribute('playsinline', 'true');
    video.muted = true;
    await video.play();

    videoWidth = video.videoWidth;
    videoHeight = video.videoHeight;
    setActive(true);
  }

  function stop(): void {
    if (stream) {
      stream.getTracks().forEach((t) => t.stop());
      stream = null;
    }
    setActive(false);
  }

  return {
    get active() {
      return active;
    },
    get videoWidth() {
      return videoWidth;
    },
    get videoHeight() {
      return videoHeight;
    },
    get stream() {
      return stream;
    },
    start,
    stop,
  };
}
